// ---------- التطبيق الرئيسي ----------
export default function App() {
  const [route, setRoute] = useState({ page: "home" });
  const [stories, setStories] = useState(SAMPLE_STORIES);
  const [commentsByStory, setCommentsByStory] = useState(SAMPLE_COMMENTS);
  const [userRatedStories, setUserRatedStories] = useState({});

  function openStory(id) {
    setRoute({ page: "story", id });
    window.scrollTo(0, 0);
  }

  function rateStory(id, n) {
    if (userRatedStories[id]) return;
    setStories((prev) =>
      prev.map((s) =>
        s.id === id
          ? {
              ...s,
              fearRating: (s.fearRating * s.ratingsCount + n) / (s.ratingsCount + 1),
              ratingsCount: s.ratingsCount + 1,
            }
          : s
      )
    );
    setUserRatedStories((prev) => ({ ...prev, [id]: true }));
  }

  const navItems = [
    { key: "home", label: "الرئيسية" },
    { key: "stories", label: "الحكاوي" },
    { key: "about", label: "عننا" },
    { key: "contact", label: "تواصل" },
  ];

  return (
    <div className="app" dir="rtl">
      {torndEdgeFilter}
      <Styles />
      <header className="site-header">
        <button className="brand" onClick={() => setRoute({ page: "home" })}>
          <span className="brand__mark">☾</span>
          <span className="brand__name">Horroriest Amir Galal</span>
        </button>
        <nav className="site-nav">
          {navItems.map((item) => (
            <button
              key={item.key}
              className={`site-nav__link ${route.page === item.key ? "site-nav__link--active" : ""}`}
              onClick={() => setRoute({ page: item.key })}
            >
              {item.label}
            </button>
          ))}
        </nav>
      </header>

      <main className="site-main">
        {route.page === "home" && (
          <HomePage stories={stories} onOpenStory={openStory} onNavigate={(p) => setRoute({ page: p })} />
        )}
        {route.page === "stories" && <StoriesPage stories={stories} onOpenStory={openStory} />}
        {route.page === "story" && (
          <StoryPage
            story={stories.find((s) => s.id === route.id)}
            comments={commentsByStory[route.id]}
            onRate={(n) => rateStory(route.id, n)}
            userRated={!!userRatedStories[route.id]}
            onBack={() => setRoute({ page: "stories" })}
          />
        )}
        {route.page === "about" && <AboutPage />}
        {route.page === "contact" && <ContactPage />}
      </main>

      <footer className="site-footer">
        <p>Horroriest Amir Galal © {new Date().getFullYear()} — كل القصص من خيال أمير جلال. أي تشابه مع الواقع هو الجزء المخيف.</p>
      </footer>
    </div>
  );
}

// ---------- الأنماط ----------
function Styles() {
  return (
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=Reem+Kufi:wght@400..700&family=Cairo:wght@800;900&family=Tajawal:wght@400;500;700&display=swap');

      :root {
        --bone: #D4C5A8;
        --void: #14100D;
        --void-2: #0E0B08;
        --rust: #8A2A22;
        --rust-dim: #5C1E18;
        --candle: #C9A227;
        --ash: #221C16;
        --ash-2: #2A231C;
        --smoke: #8A7F6E;
        --radius: 2px;
      }

      * { box-sizing: border-box; }
      html, body { margin: 0; padding: 0; }

      .app {
        background: var(--void);
        color: var(--bone);
        font-family: 'Tajawal', sans-serif;
        min-height: 100vh;
        position: relative;
        overflow-x: hidden;
      }
      .app::before {
        content: "";
        position: fixed;
        inset: 0;
        pointer-events: none;
        background-image: radial-gradient(circle at 20% 20%, rgba(201,162,39,0.04), transparent 40%),
                           radial-gradient(circle at 80% 70%, rgba(138,42,34,0.05), transparent 45%);
        z-index: 0;
      }

      button { font-family: inherit; cursor: pointer; }
      input, textarea { font-family: inherit; }

      /* ===== Header ===== */
      .site-header {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 22px clamp(20px, 5vw, 64px);
        border-bottom: 1px solid rgba(201,162,39,0.18);
        position: relative;
        z-index: 5;
      }
      .brand {
        display: flex;
        align-items: center;
        gap: 10px;
        background: none;
        border: none;
        color: var(--bone);
      }
      .brand__mark { color: var(--candle); font-size: 1.4rem; }
      .brand__name {
        font-family: 'Reem Kufi', sans-serif;
        font-size: 1.5rem;
        letter-spacing: 1px;
      }
      .site-nav { display: flex; gap: clamp(14px, 2vw, 28px); }
      .site-nav__link {
        background: none;
        border: none;
        color: var(--smoke);
        font-size: 0.95rem;
        padding: 6px 2px;
        border-bottom: 2px solid transparent;
        transition: color 0.2s, border-color 0.2s;
      }
      .site-nav__link:hover, .site-nav__link--active {
        color: var(--candle);
        border-bottom-color: var(--rust);
      }

      .site-main {
        position: relative;
        z-index: 1;
        max-width: 1080px;
        margin: 0 auto;
        padding: 0 clamp(20px, 5vw, 64px) 80px;
      }

      /* ===== Hero ===== */
      .hero {
        padding: clamp(60px, 12vh, 120px) 0 70px;
        text-align: center;
        position: relative;
      }
      .hero__eyebrow {
        color: var(--smoke);
        letter-spacing: 0.5px;
        font-size: 0.95rem;
        line-height: 1.9;
        max-width: 580px;
        margin: 0 auto 28px;
      }
      .hero__title {
        font-family: 'Cairo', sans-serif;
        font-weight: 900;
        font-size: clamp(2.6rem, 7vw, 4.6rem);
        line-height: 1.3;
        margin: 0 0 22px;
        letter-spacing: -0.5px;
        color: var(--bone);
      }
      .hero__title--text {
        font-size: clamp(1.5rem, 3.2vw, 2.3rem);
        line-height: 1.65;
        max-width: 720px;
        margin: 0 auto 28px;
        letter-spacing: 0;
      }
      .hero__title-line { display: block; color: var(--bone); }
      .hero__title-line--accent { color: var(--rust); }
      .hero__sub {
        color: var(--smoke);
        max-width: 540px;
        margin: 0 auto 34px;
        font-size: 1.05rem;
        line-height: 1.8;
      }
      .hero__sub strong { color: var(--candle); }

      .btn {
        font-size: 1rem;
        padding: 13px 30px;
        border-radius: var(--radius);
        border: 1px solid var(--candle);
        background: transparent;
        color: var(--candle);
        transition: all 0.25s;
      }
      .btn--primary {
        background: var(--rust-dim);
        border-color: var(--rust);
        color: var(--bone);
      }
      .btn--primary:hover { background: var(--rust); }
      .btn--ghost { border-color: rgba(201,162,39,0.4); color: var(--smoke); font-size: 0.9rem; padding: 10px 22px; }
      .btn--ghost:hover { border-color: var(--candle); color: var(--candle); }

      /* ===== Section titles ===== */
      .section-title, .page-title {
        font-family: 'Reem Kufi', sans-serif;
        font-size: clamp(1.6rem, 3vw, 2.2rem);
        margin-bottom: 28px;
        position: relative;
        padding-bottom: 14px;
      }
      .section-title::after, .page-title::after {
        content: "";
        position: absolute;
        bottom: 0; right: 0;
        width: 60px; height: 2px;
        background: var(--rust);
      }

      /* ===== Story grid & cards ===== */
      .story-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
        gap: 22px;
      }
      .story-card {
        background: var(--ash);
        border: 1px solid rgba(201,162,39,0.12);
        padding: 26px 24px;
        cursor: pointer;
        transition: transform 0.25s, border-color 0.25s, background 0.25s;
        position: relative;
      }
      .story-card:hover {
        transform: translateY(-4px);
        border-color: var(--rust);
        background: var(--ash-2);
      }
      .story-card:focus-visible { outline: 2px solid var(--candle); outline-offset: 3px; }
      .story-card__rule { width: 28px; height: 2px; background: var(--candle); margin-bottom: 16px; }
      .story-card__title {
        font-family: 'Reem Kufi', sans-serif;
        font-size: 1.25rem;
        margin: 0 0 12px;
        color: var(--bone);
      }
      .story-card__excerpt {
        color: var(--smoke);
        font-size: 0.92rem;
        line-height: 1.75;
        margin: 0 0 18px;
      }
      .story-card__meta {
        display: flex;
        gap: 16px;
        font-size: 0.82rem;
        color: var(--candle);
      }

      /* ===== Archive ===== */
      .archive__head {
        display: flex;
        align-items: center;
        justify-content: space-between;
        flex-wrap: wrap;
        gap: 16px;
      }
      .archive__sort { display: flex; gap: 8px; margin-bottom: 28px; }
      .chip {
        background: none;
        border: 1px solid rgba(201,162,39,0.3);
        color: var(--smoke);
        padding: 7px 16px;
        border-radius: 999px;
        font-size: 0.85rem;
      }
      .chip--active { border-color: var(--candle); color: var(--candle); }

      /* ===== Story page ===== */
      .story-page { position: relative; padding-top: 30px; }
      .back-link {
        background: none;
        border: none;
        color: var(--smoke);
        font-size: 0.9rem;
        margin-bottom: 30px;
        padding: 0;
      }
      .back-link:hover { color: var(--candle); }
      .story-page__title {
        font-family: 'Reem Kufi', sans-serif;
        font-size: clamp(1.8rem, 4vw, 2.6rem);
        margin: 0 0 12px;
      }
      .story-page__meta {
        color: var(--smoke);
        font-size: 0.88rem;
        display: flex;
        gap: 10px;
        margin-bottom: 36px;
      }
      .story-page__body {
        font-size: 1.08rem;
        line-height: 2.1;
        color: var(--bone);
        max-width: 680px;
      }
      .story-page__body p { margin: 0 0 24px; }
      .story-page__body p:first-of-type::first-letter {
        font-size: 2.6rem;
        color: var(--rust);
        font-family: 'Reem Kufi', sans-serif;
        padding-left: 6px;
      }

      /* ===== Torn reveal transition ===== */
      .torn-reveal {
        position: fixed;
        inset: 0;
        z-index: 50;
        pointer-events: none;
        animation: tornFade 0.75s ease forwards;
      }
      .torn-svg { width: 100%; height: 100%; display: block; }
      @keyframes tornFade {
        0% { opacity: 1; transform: scaleY(1); }
        70% { opacity: 1; }
        100% { opacity: 0; transform: scaleY(1.4); }
      }
      @media (prefers-reduced-motion: reduce) {
        .torn-reveal { display: none; }
      }

      /* ===== Fear rating ===== */
      .fear-rating {
        margin: 50px 0 10px;
        padding: 22px 26px;
        background: var(--ash);
        border: 1px solid rgba(201,162,39,0.15);
        max-width: 680px;
        display: flex;
        flex-wrap: wrap;
        align-items: center;
        gap: 14px;
      }
      .fear-rating__label { color: var(--smoke); font-size: 0.88rem; }
      .fear-rating__skulls { display: flex; gap: 4px; }
      .skull-btn {
        background: none;
        border: none;
        font-size: 1.3rem;
        filter: grayscale(1) opacity(0.35);
        transition: filter 0.15s, transform 0.15s;
      }
      .skull-btn:hover:not(:disabled) { transform: scale(1.15); }
      .skull-btn--lit { filter: grayscale(0) opacity(1); }
      .skull-btn:disabled { cursor: default; }
      .fear-rating__count { color: var(--candle); font-size: 0.85rem; margin-right: auto; }

      /* ===== Comments ===== */
      .comments { max-width: 680px; margin-top: 50px; }
      .comments__title {
        font-family: 'Reem Kufi', sans-serif;
        font-size: 1.3rem;
        display: flex;
        gap: 8px;
        align-items: baseline;
        margin-bottom: 20px;
      }
      .comments__count { color: var(--smoke); font-size: 0.95rem; font-family: 'Tajawal', sans-serif; }
      .comments__form {
        display: flex;
        flex-direction: column;
        gap: 10px;
        margin-bottom: 32px;
        background: var(--ash);
        padding: 18px;
        border: 1px solid rgba(201,162,39,0.12);
      }
      .comments__input, .comments__textarea {
        background: var(--void-2);
        border: 1px solid rgba(201,162,39,0.2);
        color: var(--bone);
        padding: 10px 14px;
        border-radius: var(--radius);
        font-size: 0.95rem;
        resize: vertical;
      }
      .comments__input:focus, .comments__textarea:focus {
        outline: none;
        border-color: var(--candle);
      }
      .comments__error { color: var(--rust); font-size: 0.85rem; margin: 0; }
      .comments__form .btn { align-self: flex-start; }
      .comments__list { list-style: none; padding: 0; display: flex; flex-direction: column; gap: 16px; }
      .comments__empty { color: var(--smoke); font-style: italic; }
      .comment {
        border-right: 2px solid var(--rust-dim);
        padding: 4px 16px 4px 0;
      }
      .comment__head { display: flex; gap: 10px; align-items: baseline; margin-bottom: 6px; }
      .comment__name { color: var(--candle); font-size: 0.92rem; font-weight: 700; }
      .comment__date { color: var(--smoke); font-size: 0.78rem; }
      .comment__text { margin: 0; color: var(--bone); line-height: 1.7; font-size: 0.95rem; }

      /* ===== About / Contact ===== */
      .about__photo {
        width: 180px;
        height: 180px;
        object-fit: cover;
        border-radius: 50%;
        border: 2px solid var(--rust);
        margin-bottom: 28px;
        display: block;
        filter: grayscale(0.15) contrast(1.05);
      }
      .about__content, .contact__form { max-width: 640px; }
      .about__content p { line-height: 1.9; color: var(--bone); margin-bottom: 18px; }
      .social-links {
        display: flex;
        flex-wrap: wrap;
        gap: 12px;
        max-width: 640px;
        margin-bottom: 36px;
      }
      .social-links__item {
        display: flex;
        align-items: center;
        gap: 10px;
        background: var(--ash);
        border: 1px solid rgba(201,162,39,0.2);
        color: var(--bone);
        padding: 12px 20px;
        border-radius: var(--radius);
        text-decoration: none;
        font-size: 0.95rem;
        transition: border-color 0.2s, background 0.2s, transform 0.2s;
      }
      .social-links__item:hover {
        border-color: var(--candle);
        background: var(--ash-2);
        transform: translateY(-2px);
      }
      .social-links__icon { font-size: 1.2rem; }
      .contact__form { display: flex; flex-direction: column; gap: 18px; }
      .field { display: flex; flex-direction: column; gap: 8px; color: var(--smoke); font-size: 0.92rem; }
      .field input, .field textarea {
        background: var(--ash);
        border: 1px solid rgba(201,162,39,0.2);
        color: var(--bone);
        padding: 11px 14px;
        border-radius: var(--radius);
        font-size: 0.98rem;
      }
      .field input:focus, .field textarea:focus { outline: none; border-color: var(--candle); }
      .contact__success { color: var(--candle); font-size: 1.05rem; }

      /* ===== Footer ===== */
      .site-footer {
        text-align: center;
        padding: 30px 20px;
        color: var(--smoke);
        font-size: 0.82rem;
        border-top: 1px solid rgba(201,162,39,0.12);
      }

      /* ===== Responsive ===== */
      @media (max-width: 640px) {
        .site-nav { gap: 12px; }
        .site-nav__link { font-size: 0.85rem; }
        .hero { padding-top: 50px; }
      }
    `}</style>
  );
}
